DROP TABLE IF EXISTS public.transactions CASCADE;
DROP TABLE IF EXISTS public.leads CASCADE;
DROP TABLE IF EXISTS public.financial_records CASCADE;
DROP TABLE IF EXISTS public.marketing_campaigns CASCADE;
DROP TABLE IF EXISTS public.employees CASCADE;

CREATE TABLE public.employees (
    id TEXT PRIMARY KEY,
    full_name TEXT,
    email TEXT,
    phone TEXT,
    department TEXT,
    position TEXT,
    hire_date DATE,
    status TEXT,
    salary NUMERIC,
    manager_id TEXT
);

CREATE TABLE public.marketing_campaigns (
    id TEXT PRIMARY KEY,
    month TEXT,
    channel TEXT,
    campaign_name TEXT,
    cost NUMERIC,
    leads INTEGER,
    bookings INTEGER,
    conversion_rate NUMERIC,
    cpl NUMERIC,
    cpb NUMERIC,
    clicks INTEGER,
    notes TEXT
);

CREATE TABLE public.leads (
    id TEXT PRIMARY KEY,
    received_date TIMESTAMPTZ,
    full_name TEXT,
    phone TEXT,
    source TEXT,
    campaign_id TEXT REFERENCES public.marketing_campaigns(id),
    requirement TEXT,
    status TEXT,
    employee_id TEXT REFERENCES public.employees(id),
    agency TEXT,
    appointment_date TIMESTAMPTZ,
    follow_up_date TIMESTAMPTZ,
    notes TEXT
);

CREATE TABLE public.transactions (
    id TEXT PRIMARY KEY,
    transaction_date DATE,
    lead_id TEXT REFERENCES public.leads(id),
    employee_id TEXT REFERENCES public.employees(id),
    product_code TEXT,
    zone TEXT,
    price NUMERIC,
    deposit NUMERIC,
    commission NUMERIC,
    status TEXT,
    notes TEXT
);

CREATE TABLE public.financial_records (
    id TEXT PRIMARY KEY,
    month TEXT,
    category TEXT,
    type TEXT,
    actual_amount NUMERIC,
    target_amount NUMERIC,
    completion_rate NUMERIC,
    difference NUMERIC,
    notes TEXT,
    approver_id TEXT REFERENCES public.employees(id)
);

